clear alllam=780e-9:1e-9:820e-9; lam_nm=lam*1e9; [crap,ind1]=min(abs(lam_nm-800));a1_deg=50; a1=a1_deg*pi/180;groove_den1=1480; % grooves per mmd1=1e-3/groove_den1;b1=asin( sin(a1)-lam/d1  );delta_groove=1; relative_angle_deg=0.0835;      % scenario 1%delta_groove=0; relative_angle_deg=0.0023;      % scenario 2relative_angle=relative_angle_deg*pi/180;a2=-b1-relative_angle;groove_den2=1480+delta_groove; % grooves per mmd2=1e-3/groove_den2;b2=asin( sin(a2)-lam/d2  );offset_angle_mid=(-b2)-a1+relative_angle;a3=(-b2)-2*offset_angle_mid;b3=asin( sin(a3)-lam/d2  );a4=-b3+relative_angle;b4=asin( sin(a4)-lam/d1  );offset_angle_final=-b4-a1;%%figure(1);set(gcf,'color',[1 1 1])set(gca,'fontsize',14)plot(lam_nm,1e6*(offset_angle_final-offset_angle_final(ind1)),'-r','LineWidth',1)xlabel('Wavelength [nm]','fontsize',18)ylabel('Angle deviation from 800nm [micro-rad]','fontsize',18)title('0.4 microrad angular chirp (790nm - 810nm) per 1 gr/mm offset','fontsize',18)
